import React, { useState } from 'react';
import axios from 'axios';
import SubmitionBar from "../SubmitionBar/SubmitionBar";
import Button from '../Button/Button.jsx'
import { useNavigate } from 'react-router-dom';
// import "./Register.css";

const API = axios.create({
    baseURL: 'http://localhost:3001'
});

const Register = ({ handleUserRegister }) => {
    const navigate = useNavigate();
    const [inputData, setInputData] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const [newUser, setNewUser] = useState({
        nome: "",
        email: "",
        senha: ""
    });

    const handleSubmition = (fieldName) => (value) => {
        setNewUser(prev => ({
            ...prev,
            [fieldName]: value
        }));
        console.log(`${fieldName} atualizado:`, value);
    };

    const handleRegister = async () => {
        // Validação básica
        if (!newUser.nome || !newUser.email || !newUser.senha) {
            setError("Todos os campos são obrigatórios!");
            return;
        }

        // Validação de email simples
        if (!newUser.email.includes('@') || !newUser.email.includes('.')) {
            setError("Email inválido!");
            return;
        }

        // Validação de senha
        if (newUser.senha.length < 6) {
            setError("A senha deve ter pelo menos 6 caracteres!");
            return;
        }

        setLoading(true);
        setError("");

        try {
            // Enviar dados para o backend
            const response = await API.post('/registrar', {
                nome: newUser.nome,
                email: newUser.email,
                senha: newUser.senha
            });

            console.log("Resposta do servidor:", response.data);

            if (response.data.message === "Registro bem sucedido.") {
                alert("Registro realizado com sucesso!");
                
                // Buscar o ID do usuário recém-criado
                const userResponse = await API.post('/buscar-id', {
                    email: newUser.email
                });
                
                if (userResponse.data.user) {
                    // Salvar dados do usuário
                    handleUser(userResponse.data.user)
                    localStorage.setItem('userId', userResponse.data.user.id);
                    localStorage.setItem('userName', userResponse.data.user.nome);
                    navigate('/tasks');

                }
            } else if (response.data.message === "Email já registrado.") {
                setError("Este email já está registrado. Tente fazer login.");
            } else {
                setError(response.data.message || "Erro ao registrar. Tente novamente.");
            }
        } catch (error) {
            console.error("Erro no registro:", error);
            setError("Erro de conexão com o servidor. Tente novamente.");
        } finally {
            setLoading(false);
        }
    };

    

    return (
        <div className = "bg-home">
                    <div className = "container-registro" >
                        <header>Registro</header>
                        <SubmitionBar handleAddition={handleSubmition("nome") } type="text" > Digite seu nome. Aperte 'Enter' finalização. </SubmitionBar>
                        <SubmitionBar handleAddition={handleSubmition("email") } type="email" > Digite seu email. </SubmitionBar>
                        <SubmitionBar handleAddition={handleSubmition("senha") } type="password" > Digite sua senha. </SubmitionBar>
                        <div> 
                            <Button
                                onClick={handleRegister}
                                disabled={loading}
                            >
                            Submeter </Button> 
                        </div>
                    </div>
                </div>
    );
};

export default Register;
